import{_ as s,c as a,o as n,d as e}from"./app.661b9247.js";const l="/FrontEndLearnNotes/assets/asar.4283bedf.png",p="/FrontEndLearnNotes/assets/webpack-bundle-analyzer.d0350968.png",r="/FrontEndLearnNotes/assets/rollup-plugin-visualizer.945071f3.jpg",o="/FrontEndLearnNotes/assets/electron-version.2e3e5a5a.jpg",_=JSON.parse('{"title":"Electron项目打包优化配置","description":"","frontmatter":{},"headers":[{"level":2,"title":"node_modules优化：","slug":"node-modules优化","link":"#node-modules优化","children":[{"level":3,"title":"依赖项，按需加载:","slug":"依赖项-按需加载","link":"#依赖项-按需加载","children":[]},{"level":3,"title":"vite打包优化配置：","slug":"vite打包优化配置","link":"#vite打包优化配置","children":[]},{"level":3,"title":"webpack打包优化配置：","slug":"webpack打包优化配置","link":"#webpack打包优化配置","children":[]},{"level":3,"title":"vue项目优化配置：","slug":"vue项目优化配置","link":"#vue项目优化配置","children":[]},{"level":3,"title":"react项目优化配置：","slug":"react项目优化配置","link":"#react项目优化配置","children":[]}]}],"relativePath":"Document/Electron/Electron项目打包优化配置.md","lastUpdated":1664182267000}'),t={name:"Document/Electron/Electron项目打包优化配置.md"},c=e(`<h1 id="electron项目打包优化配置" tabindex="-1">Electron项目打包优化配置 <a class="header-anchor" href="#electron项目打包优化配置" aria-hidden="true">#</a></h1><h2 id="node-modules优化" tabindex="-1">node_modules优化： <a class="header-anchor" href="#node-modules优化" aria-hidden="true">#</a></h2><p>分析一下打包后的文件包，在release -&gt; 【版本号命名的文件夹】 -&gt; win-ia32-unpacked -&gt; resources 下有个app.asar文件，这其实是个压缩包，目的是保护代码隐私，在build中可配置是否需要压缩为asar包。<br> 在electron-builder.yml中加入：</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">asar: </span><span style="color:#D19A66;">true</span><span style="color:#98C379;">,</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">//</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">asar打包</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>用asar工具包解压。</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 安装</span></span>
<span class="line"><span style="color:#ABB2BF;">npm </span><span style="color:#98C379;">install</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">asar</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-g</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 解压</span></span>
<span class="line"><span style="color:#ABB2BF;">asar </span><span style="color:#98C379;">extract</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">app.asar</span><span style="color:#ABB2BF;"> &lt;</span><span style="color:#98C379;">解压后的目</span><span style="color:#ABB2BF;">录&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>解压然后看下包中有哪些内容：<br><img src="`+l+`" alt=""><br> dist和resources是配置项中指定的需要复制打包的内容，这没有问题，可是node_modules中的依赖项已经在webpack打包构建时一同打包进了dist下，它不应该在这里，而且electron-builder配置项files中也没有指定复制此文件夹。带着这个疑问，查看一下<a href="https://www.electron.build/configuration/contents" target="_blank" rel="noreferrer">文档</a>，找到了原因，原来files有默认值：</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">[</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;**/*&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/node_modules/*/{CHANGELOG.md,README.md,README,readme.md,readme}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/node_modules/*/{test,__tests__,tests,powered-test,example,examples}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/node_modules/*.d.ts&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/node_modules/.bin&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/*.{iml,o,hprof,orig,pyc,pyo,rbc,swp,csproj,sln,xproj}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!.editorconfig&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/._*&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/{.DS_Store,.git,.hg,.svn,CVS,RCS,SCCS,.gitignore,.gitattributes}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/{__pycache__,thumbs.db,.flowconfig,.idea,.vs,.nyc_output}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/{appveyor.yml,.travis.yml,circle.yml}&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">&quot;!**/{npm-debug.log,yarn.lock,.yarn-integrity,.yarn-metadata.json}&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><div class="language-vhdl line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vhdl</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#C678DD;">package</span><span style="color:#ABB2BF;">.json </span><span style="color:#C678DD;">and</span><span style="color:#ABB2BF;"> **/node_modules/**/* (only production dependencies will be copied) </span><span style="color:#C678DD;">is</span><span style="color:#ABB2BF;"> added </span><span style="color:#C678DD;">to</span><span style="color:#ABB2BF;"> your custom </span><span style="color:#C678DD;">in</span><span style="color:#ABB2BF;"> any </span><span style="color:#C678DD;">case</span><span style="color:#ABB2BF;">. </span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">意思是：</span><span style="color:#C678DD;">package</span><span style="color:#ABB2BF;">.json和node_modules（仅仅生产依赖项会被复制）在任何情况下都会被添加至自定义（应该是files配置项下吧）中。</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>那这就很清楚了，我只需要在files中添加&quot;!node_modules&quot;即可，打包后体积是128M，足足小了37M，安装执行，没有问题。</p><hr><h5 id="图片优化" tabindex="-1">图片优化 <a class="header-anchor" href="#图片优化" aria-hidden="true">#</a></h5><p>图片优化在整个项目的优化中是优先级较高的，所谓的图片优化，其实是体积与质量之间的博弈，因此要想减小包中图片的体积，是要牺牲一部分图片质量的，也就是清晰度。做出如下优化：</p><ul><li>首先对gif图在不影响用户观看的前提下做了一定压缩；</li><li>将一些png（流程图，logo，线条简单的）转为svg；</li><li>将一些截图png转为jpg；</li></ul><p>最终将整体包体积dmg减小至102M，ia32exe为80M左右</p><hr><h3 id="依赖项-按需加载" tabindex="-1">依赖项，按需加载: <a class="header-anchor" href="#依赖项-按需加载" aria-hidden="true">#</a></h3><p>检查一下依赖项的位置和引用，首先对于package.json中依赖项进行排查，查看dependencies和devDependencies中的依赖项有没有错位的（开发依赖项写在了生产依赖项中），由于打包时只打包dependencies中的依赖项，所以在生产环境中用不到的依赖项一律塞至devDependencies。<br> 然后再检查引用库的按需加载：</p><p>如果是webpack：可以使用<a href="https://www.npmjs.com/package/webpack-bundle-analyzer" target="_blank" rel="noreferrer">webpack-bundle-analyzer</a>可视化插件看一下依赖体积图示</p><p><img src="`+p+'" alt="image.png"></p><p>如果是vite：就使用<a href="https://www.npmjs.com/package/rollup-plugin-visualizer" target="_blank" rel="noreferrer">rollup-plugin-visualizer</a></p><p><img src="'+r+'" alt="rollup-plugin-visualizer.jpg"></p><hr><h3 id="vite打包优化配置" tabindex="-1">vite打包优化配置： <a class="header-anchor" href="#vite打包优化配置" aria-hidden="true">#</a></h3><h3 id="webpack打包优化配置" tabindex="-1">webpack打包优化配置： <a class="header-anchor" href="#webpack打包优化配置" aria-hidden="true">#</a></h3><h3 id="vue项目优化配置" tabindex="-1">vue项目优化配置： <a class="header-anchor" href="#vue项目优化配置" aria-hidden="true">#</a></h3><h3 id="react项目优化配置" tabindex="-1">react项目优化配置： <a class="header-anchor" href="#react项目优化配置" aria-hidden="true">#</a></h3><h4 id="electron-builder打包配置优化" tabindex="-1">electron-builder打包配置优化： <a class="header-anchor" href="#electron-builder打包配置优化" aria-hidden="true">#</a></h4><h5 id="双package-json" tabindex="-1">双package.json <a class="header-anchor" href="#双package-json" aria-hidden="true">#</a></h5><p>官方重构了生产依赖项，提出双package.json结构（<a href="https://www.electron.build/tutorials/two-package-structure.html" target="_blank" rel="noreferrer">two package.json</a>）。顾名思义，通过两个package.json管理依赖项。一个用来管理开发依赖项，一个管理应用程序依赖项，最终打包时只打包应用程序依赖项。</p><ul><li><p>开发依赖</p><p>此package.json在项目根目录下，文件中声明开发依赖和打包脚本；</p></li><li><p>应用程序依赖；</p><p>在app文件夹下，声明应用程序依赖，打包时仅打包此文件中声明的依赖。所有的元字段应当在此文件声明（version，name等）。</p></li></ul><h5 id="版本" tabindex="-1">版本 <a class="header-anchor" href="#版本" aria-hidden="true">#</a></h5><p>electron版本也会对打包体积有影响，这里用electron^8和10.1.5小试一下，下图左为8版本，右为10版本。或许系统版本对打包体积也有影响，这里不做尝试了，有条件同学的可以试一下。</p><p><img src="'+o+'" alt="electron-version.jpg"></p>',34),i=[c];function d(u,B,b,h,y,m){return n(),a("div",null,i)}const v=s(t,[["render",d]]);export{_ as __pageData,v as default};
